* { box-sizing: border-box; }

/* The HTML `hidden` attribute is normally `display: none`, but any explicit
   `display` rule in author CSS overrides it. Force hidden to always win. */
[hidden] { display: none !important; }

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
}

#app {
  display: flex;
  height: 100vh;
}

#sidebar {
  width: 320px;
  flex-shrink: 0;
  background: var(--panel);
  border-right: 1px solid var(--border);
  overflow-y: auto;
}

#sidebar-header {
  padding: 16px;
  border-bottom: 1px solid var(--border);
}

#sidebar-header h1 {
  font-size: 16px;
  margin: 0 0 4px;
}

#task-count {
  font-size: 12px;
  color: var(--text-dim);
}

#task-list {
  list-style: none;
  margin: 0;
  padding: 8px;
}

.task-item {
  padding: 10px 12px;
  border-radius: 8px;
  cursor: pointer;
  margin-bottom: 4px;
  border: 1px solid transparent;
}

.task-item:hover {
  background: var(--panel-2);
}

.task-item.active {
  background: var(--accent-dim);
  border-color: var(--accent);
}

.task-item .occ {
  font-size: 13px;
  font-weight: 600;
}

.task-item .folder {
  font-size: 11px;
  color: var(--text-dim);
  font-family: ui-monospace, SFMono-Regular, monospace;
  margin-top: 2px;
}

.task-item .sector {
  font-size: 11px;
  color: var(--text-dim);
  margin-top: 4px;
}

#content {
  flex: 1;
  overflow-y: auto;
  padding: 0;
}

#empty-state {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: var(--text-dim);
  font-size: 14px;
}

#task-header {
  padding: 20px 28px;
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  background: var(--bg);
  z-index: 5;
}

#task-occupation {
  margin: 0 0 6px;
  font-size: 20px;
}

#task-meta {
  font-size: 12px;
  color: var(--text-dim);
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
}

#task-meta span b {
  color: var(--text);
}

#tabs {
  display: flex;
  gap: 4px;
  padding: 0 28px;
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 78px;
  background: var(--bg);
  z-index: 5;
}

.tab-btn {
  background: none;
  border: none;
  color: var(--text-dim);
  padding: 10px 14px;
  font-size: 13px;
  cursor: pointer;
  border-bottom: 2px solid transparent;
}

.tab-btn:hover {
